// Runtime shared by every C# parser generated by parsuna.
//
// A generated grammar namespace supplies token/rule-kind enums (backed by
// `ushort` / `ushort`), a DfaMatcher, a skip predicate, and a Step
// callback. This library provides everything else.

using System;
using System.Collections;
using System.Collections.Generic;
using System.IO;
using System.Text;

namespace Parsuna.Runtime;

/// <summary>Source position: byte offset plus 1-based line/column.</summary>
public readonly record struct Pos(int Offset, int Line, int Column);

/// <summary>Half-open span <c>[Start, End)</c> over the source.</summary>
public readonly record struct Span(Pos Start, Pos End)
{
    public static Span Point(Pos p) => new(p, p);
}

/// <summary>
/// A lexed token: kind id, source span, matched text, and an optional
/// grammar-position <see cref="Label"/>.
/// </summary>
/// <remarks>
/// <para><c>Kind</c> is a <c>ushort</c> matching the generated
/// <c>TokenKind</c> enum's underlying value. EOF = 0; grammar tokens have
/// ids starting at 1; the lexer emits <see cref="Lexer.ErrorKind"/>
/// (0xFFFF) when no DFA pattern matched at the current position. The
/// parser runtime turns those into a paired <see cref="ErrorEvent"/>
/// +<see cref="GarbageEvent"/> sequence at pump time and never lets
/// them reach generated dispatch.</para>
///
/// <para><c>Label</c> is the grammar-position name from a
/// <c>name:NAME</c> form, or <c>null</c> for unlabeled positions. Set by
/// the dispatch's labeled <see cref="Cursor.TryConsumeLabeled"/> on the
/// success path, so consumers can identify a token by its position name
/// without walking surrounding rule context.</para>
/// </remarks>
public sealed record Token(ushort Kind, Span Span, string Text, string? Label = null);

/// <summary>A recoverable parse or lex error with its source span.</summary>
public sealed record ParseError(string Message, Span Span)
{
    public override string ToString()
    {
        var (s, e) = (Span.Start, Span.End);
        var loc = s == e ? $"{s.Line}:{s.Column}" : $"{s.Line}:{s.Column}-{e.Line}:{e.Column}";
        return $"error[{loc}]: {Message}";
    }
}

/// <summary>
/// A single pull-parser event. Pattern-match on the concrete subtype to
/// extract its payload:
/// <code>
///   switch (ev) {
///       case EnterEvent e: ...; break;
///       case ExitEvent e:  ...; break;
///       case TokenEvent t: ...; break;
///       case ErrorEvent x: ...; break;
///   }
/// </code>
/// </summary>
public abstract record Event;

/// <summary>Opens the subtree of the given rule; <c>Pos</c> is the start of the first child.</summary>
public sealed record EnterEvent(int Rule, Pos Pos) : Event;

/// <summary>Closes the subtree of the given rule; <c>Pos</c> is the end of the last child.</summary>
public sealed record ExitEvent(int Rule, Pos Pos) : Event;

/// <summary>A token consumed from the input, including skip tokens
/// and the synced-to-expected token after a recovery.</summary>
public sealed record TokenEvent(Token Token) : Event;

/// <summary>A token consumed during error recovery — emitted between
/// an <see cref="ErrorEvent"/> and the recovery's sync point. Distinct
/// from <see cref="TokenEvent"/> so consumers can drop it from their
/// AST or render it as an error span without tracking recovery state
/// externally.</summary>
public sealed record GarbageEvent(Token Token) : Event;

/// <summary>A recoverable parse or lex error.</summary>
public sealed record ErrorEvent(ParseError Error) : Event;

/// <summary>
/// Grammar-specific compiled lexer DFA. Generated code supplies this as a
/// method: a per-state switch (one per declared lexer mode) that avoids
/// the data-dependent table load a table-driven DFA pays on every byte.
/// </summary>
/// <remarks>
/// <para>The matcher branches on <paramref name="mode"/> and falls into
/// the per-mode state machine. Grammars without <c>@mode(...)</c>
/// pre-annotations have a single mode (id 0); the dispatch collapses to
/// a direct call.</para>
///
/// <para>Writes three ints to <paramref name="output"/>:
/// [0] bestLen (0 = no accept), [1] bestKind (error sentinel when no
/// accept reached), [2] scanned (== bufLen - start when the scan ran out
/// of buffer rather than hitting a dead transition; used to detect
/// buffer exhaustion mid-token).</para>
/// </remarks>
public delegate void DfaMatcher(byte[] buf, int start, int bufLen, int mode, int[] output);

/// <summary>Byte-level lexer. Reads from a <see cref="Stream"/> in 16 KiB chunks. The grammar-specific DFA is supplied as a <see cref="DfaMatcher"/>.</summary>
public sealed class Lexer
{
    private const int Chunk = 16384;

    /// <summary>
    /// Token-kind sentinel emitted when no DFA pattern matches at the current
    /// position. Distinct from any grammar token id (0..0xFFFE), so dispatch
    /// arms naturally fall through to the recovery path.
    /// </summary>
    public const ushort ErrorKind = 0xFFFF;

    private readonly Stream _stream;
    private byte[] _buf;
    private int _bufLen;
    private int _bufPos;
    private bool _eof;
    private int _offset;
    private int _line = 1;
    private int _col = 1;
    private readonly DfaMatcher _matcher;
    private readonly int[] _matchOut = new int[3];
    /// <summary>Mode stack — top of stack is the active lexer mode. Always
    /// non-empty; initialised with the default mode (id 0). Pop is a no-op
    /// when only the default remains so a stray <c>-> pop</c> action can't
    /// underflow.</summary>
    private int[] _modeStack = { 0 };
    private int _modeTop;

    public Lexer(Stream stream, DfaMatcher matcher)
    {
        _stream = stream;
        _buf = new byte[Chunk * 2];
        _matcher = matcher;
    }

    /// <summary>Push <paramref name="mode"/> onto the mode stack.
    /// Subsequent <see cref="NextToken"/> calls scan with that mode's DFA
    /// until a matching <see cref="PopMode"/>.</summary>
    public void PushMode(int mode)
    {
        if (_modeTop + 1 >= _modeStack.Length)
        {
            Array.Resize(ref _modeStack, _modeStack.Length * 2);
        }
        _modeStack[++_modeTop] = mode;
    }

    /// <summary>Pop the topmost mode off the stack, leaving at least the
    /// default mode in place. Underflow is silently ignored.</summary>
    public void PopMode()
    {
        if (_modeTop > 0) _modeTop--;
    }

    /// <summary>Number of modes currently on the stack — always &gt;= 1.
    /// Used by the parser's recovery path to remember "the depth at the
    /// time we entered this rule".</summary>
    public int ModeDepth => _modeTop + 1;

    /// <summary>Pop modes until the stack reaches <paramref name="targetDepth"/>,
    /// clamped at the bottom by the default mode. No-op when the stack
    /// is already at or below <paramref name="targetDepth"/>.</summary>
    public void PopModesTo(int targetDepth)
    {
        var target = Math.Max(1, targetDepth);
        if (_modeTop + 1 > target) _modeTop = target - 1;
    }

    private Pos CurPos() => new(_offset, _line, _col);

    private bool ReadMore()
    {
        if (_eof) return false;
        if (_buf.Length - _bufLen < Chunk)
        {
            int newLen = _buf.Length;
            while (newLen - _bufLen < Chunk) newLen *= 2;
            Array.Resize(ref _buf, newLen);
        }
        int n = _stream.Read(_buf, _bufLen, _buf.Length - _bufLen);
        if (n <= 0) { _eof = true; return false; }
        _bufLen += n;
        return true;
    }

    private void Ensure(int want)
    {
        while (!_eof && _bufLen - _bufPos < want)
        {
            if (!ReadMore()) break;
        }
    }

    // Fast-path: bump column directly for pure ASCII non-newline slices;
    // byte-by-byte walk otherwise so multi-byte codepoints count as one column.
    private void Advance(int n)
    {
        int end = _bufPos + n;
        bool needsWalk = false;
        for (int k = _bufPos; k < end; k++)
        {
            byte b = _buf[k];
            if (b == (byte)'\n' || b >= 0x80) { needsWalk = true; break; }
        }
        if (!needsWalk)
        {
            _col += n;
            _offset += n;
            _bufPos = end;
        }
        else
        {
            while (_bufPos < end)
            {
                byte b = _buf[_bufPos++]; _offset++;
                if (b == (byte)'\n') { _line++; _col = 1; }
                else if ((b & 0xC0) != 0x80) _col++;
            }
        }
        if (_bufPos > 65536)
        {
            Array.Copy(_buf, _bufPos, _buf, 0, _bufLen - _bufPos);
            _bufLen -= _bufPos; _bufPos = 0;
        }
    }

    private (int Len, ushort Kind) LongestMatch()
    {
        while (true)
        {
            _matcher(_buf, _bufPos, _bufLen, _modeStack[_modeTop], _matchOut);
            int scanned = _matchOut[2];
            int viewLen = _bufLen - _bufPos;
            if (!_eof && scanned == viewLen)
            {
                if (ReadMore()) continue;
            }
            return (_matchOut[0], (ushort)_matchOut[1]);
        }
    }

    /// <summary>
    /// Produce the next token. Returns repeated EOF once input is fully
    /// consumed; lex failures (no DFA pattern matched) come through with
    /// <c>Token.Kind == <see cref="ErrorKind"/></c> (0xFFFF).
    /// </summary>
    /// <remarks>
    /// Auto-pop on mismatch: if no DFA match in the active mode and the
    /// mode stack has more than just the default mode, drop one mode and
    /// retry — "if you can't find a token in this mode, you weren't
    /// supposed to be in this mode anymore." Keeps a stray byte from
    /// stranding the lexer in an interior mode for the rest of the input.
    /// </remarks>
    public Token NextToken()
    {
        Ensure(Chunk);
        if (_bufLen - _bufPos == 0) { var p = CurPos(); return new Token(0, Span.Point(p), ""); }
        var best = LongestMatch();
        while (best.Len == 0 && _modeTop > 0)
        {
            _modeTop--;
            best = LongestMatch();
        }
        var start = CurPos();
        if (best.Len == 0)
        {
            byte b = _buf[_bufPos];
            int cpLen = b < 0x80 ? 1 : b < 0xE0 ? 2 : b < 0xF0 ? 3 : 4;
            int take = Math.Min(cpLen, _bufLen - _bufPos);
            string text = Encoding.UTF8.GetString(_buf, _bufPos, take);
            Advance(take);
            return new Token(ErrorKind, new Span(start, CurPos()), text);
        }
        string tokText = Encoding.UTF8.GetString(_buf, _bufPos, best.Len);
        Advance(best.Len);
        return new Token(best.Kind, new Span(start, CurPos()), tokText);
    }
}

/// <summary>Grammar-specific callbacks a generated parser wires into
/// the runtime.</summary>
/// <remarks>
/// <c>Step</c> runs one state body of the dispatch and returns the
/// event that body produced, or <c>null</c> if the body was a pure
/// transition step — the runtime's <c>NextEvent</c> loop calls
/// <c>Step</c> again in that case.
///
/// <para><c>Step</c> receives a <see cref="Cursor"/> — a thin wrapper
/// that exposes just the runtime hooks generated dispatch needs
/// (Look/State/PushRet/Enter/Exit/etc.). Outside callers only see
/// <see cref="Parser"/>, which has no such methods, so the parser's
/// internal state stays sealed.</para>
/// </remarks>
public sealed record ParserConfig(
    int K,
    Predicate<ushort> IsSkip,
    bool HasSkips,
    Func<Cursor, Event?> Step,
    Action<ushort, Lexer> ApplyActions)
{
    /// <summary>End-of-input token kind. Always 0; a constant rather than a
    /// per-grammar value so generated code and consumers don't sprinkle
    /// magic numbers.</summary>
    public const ushort EofKind = 0;

    /// <summary>Convenience constructor for grammars that declare no
    /// modes — supplies a no-op <see cref="ApplyActions"/>.</summary>
    public ParserConfig(int K, Predicate<ushort> IsSkip, bool HasSkips, Func<Cursor, Event?> Step)
        : this(K, IsSkip, HasSkips, Step, static (_, _) => {}) { }
}

/// <summary>
/// Runtime-level toggles the caller picks per parser construction.
/// Today it just controls skip-token emission; future flags can be added
/// without breaking call sites because of <c>init</c>-only defaults.
/// </summary>
/// <remarks>
/// <c>DropSkips = true</c> suppresses skip tokens at the source: the
/// lexer still matches them (they delimit structural tokens), but the
/// parser's enumeration never returns them as <see cref="TokenEvent"/>s.
/// Default <c>false</c> matches the historic behaviour.
/// </remarks>
public sealed record ParserOptions
{
    public bool DropSkips { get; init; } = false;
    /// <summary>
    /// When <c>true</c>, every <see cref="TokenEvent"/> whose
    /// <see cref="Token.Label"/> is <c>null</c> (i.e. that didn't match
    /// a <c>name:NAME</c> position in the grammar) is silently consumed.
    /// Structural events (<see cref="EnterEvent"/>, <see cref="ExitEvent"/>,
    /// <see cref="ErrorEvent"/>) and <see cref="GarbageEvent"/> still
    /// flow through. The "give me an AST shape, drop the punctuation"
    /// mode for tree-building consumers. Implies skip-token suppression
    /// (skip tokens never carry a label).
    /// </summary>
    public bool DropUnlabeledTokens { get; init; } = false;
}

/// <summary>
/// Pull-based parser. Obtain one via a generated <c>ParseXxx</c> factory
/// and iterate it (or call <see cref="NextEvent"/> directly) to walk the parse.
/// </summary>
/// <remarks>
/// The parser keeps a ring of <c>K</c> lookahead slots (sized to the
/// grammar's LL(k)) and a return stack. Each call to
/// <see cref="NextEvent"/> runs in one of three modes — pump (refill
/// lookahead, possibly yielding a skip), recovery (one
/// <see cref="GarbageEvent"/> or synced <see cref="TokenEvent"/>),
/// or drive (one call to the generated <see cref="ParserConfig.Step"/>
/// callback) — and yields at most one event before looping again.
///
/// <para><b>Skip handling</b> is driven by pump-mode: when the lexer
/// hands the runtime a skip token <c>NextEvent</c> returns it as a
/// <see cref="TokenEvent"/> directly. The lookahead refills one lex
/// token at a time, so a long comment run never piles up — each skip
/// is yielded in turn before the next pump iteration runs.</para>
/// </remarks>
public sealed class Parser : IEnumerable<Event>, IEnumerator<Event>
{
    /// <summary>Sentinel state meaning "the parser has terminated".</summary>
    public const int Terminated = -1;

    /// <summary>In-flight error recovery state. Set by <see cref="Cursor.RecoverTo"/>
    /// and the slow path of <see cref="Cursor.TryConsume"/>; cleared once the
    /// lookahead lands on a sync token (or EOF). Each call to
    /// <see cref="NextEvent"/> drains exactly one garbage token before
    /// yielding, so a long run of unexpected input doesn't pile up in
    /// the queue.</summary>
    internal struct Recovery
    {
        /// <summary>Token kinds to recover *to*. Recovery consumes garbage
        /// until the lookahead matches one of these (or EOF).</summary>
        public ushort[] Sync;
        /// <summary>Non-zero when the recovery was triggered by an
        /// <see cref="Cursor.TryConsume"/> for that kind: if the sync set
        /// lands on the expected kind, the recovery finalisation also
        /// consumes the token (so the surrounding rule proceeds as if it
        /// had matched). Zero (no expected kind) for the dispatch-error
        /// path. Stored as a one-past-EOF encoding: 0 means "no
        /// expected", any other value is the literal expected kind + 1.</summary>
        public int ExpectedPlusOne;
    }

    private readonly Lexer _lex;
    // Lookahead ring. Null slots are awaiting refill — pump-mode in
    // NextEvent pulls lex tokens one-at-a-time until every slot holds a
    // structural token. Generated Step code only ever runs when all
    // slots are filled, so Cursor.Look(i) can return the value
    // unconditionally.
    //
    // Empty slots are always a contiguous suffix — TakeToken parks the
    // new null at index K-1 and pump fills the leftmost empty slot.
    //
    // Fields are `internal` rather than `private` so the sibling
    // <see cref="Cursor"/> wrapper can access them directly without
    // an extra method-call hop. External code can't see them either
    // way — the assembly seam keeps them out of consumers' hands.
    internal readonly Token?[] _look;
    internal Pos _prevEnd;
    internal int _state;
    internal readonly Stack<int> _ret = new();
    /// <summary>Lex mode-stack depth captured at each PushRet, in
    /// lockstep with <see cref="_ret"/>. Recovery uses the top entry
    /// to unwind interior mode pushes back to the depth in place
    /// when the rule we're now inside was entered.</summary>
    internal readonly Stack<int> _retModeDepth = new();

    private Event? _current;

    internal Recovery _recovery;
    internal bool _recoveryActive;

    // Holds the lex-failure token (Kind = Lexer.ErrorKind) whose paired
    // ErrorEvent the previous MoveNext() call returned; this call owes
    // the matching GarbageEvent. Lex-failure tokens never enter _look,
    // so dispatch can read Look(i).Kind as a real grammar token id
    // without an ErrorKind guard, and a stray bad byte doesn't push the
    // parser out of an active Star into SYNC recovery.
    private Token? _pendingLexGarbage;

    internal readonly ParserConfig _cfg;
    internal readonly ParserOptions _opts;

    public Parser(Lexer lex, int entry, ParserConfig cfg)
        : this(lex, entry, cfg, new ParserOptions()) { }

    public Parser(Lexer lex, int entry, ParserConfig cfg, ParserOptions opts)
    {
        _lex = lex;
        _cfg = cfg;
        _opts = opts;
        _state = entry;
        _look = new Token?[cfg.K];
        _prevEnd = default;
    }

    // Pop the current lookahead token and shift the buffer up by one.
    // Slot K-1 is left null so pump-mode can refill it (yielding one
    // skip per call) before the next Step reads lookahead. Internal —
    // callers wrap the result in the appropriate event subtype.
    internal Token TakeToken()
    {
        var t = _look[0]!;
        _prevEnd = t.Span.End;
        for (int i = 0; i < _cfg.K - 1; i++) _look[i] = _look[i + 1];
        _look[_cfg.K - 1] = null;
        return t;
    }

    internal Event Consume() => new TokenEvent(TakeToken());

    internal Event ErrorHere(string msg) =>
        new ErrorEvent(new ParseError(msg, _look[0]!.Span));

    private static bool ContainsKind(ushort[] set, ushort k)
    {
        foreach (var x in set) if (x == k) return true;
        return false;
    }

    // True iff some lookahead slot still needs to be filled. Empty
    // slots are always a contiguous suffix, so checking slot K-1 is
    // the O(1) form of "any slot is null".
    private bool PumpPending() => _look[_cfg.K - 1] is null;

    /// <summary>
    /// Advance to the next event, returning <c>true</c> if one was
    /// produced (read it via <see cref="Current"/>) or <c>false</c>
    /// once the input is fully consumed. The whole pull loop lives
    /// here — there's no separate <c>NextEvent</c> indirection.
    /// </summary>
    /// <remarks>
    /// The loop runs three modes — pump (refill lookahead, possibly
    /// yielding a skip), recovery (one Garbage / synced-Token event
    /// per call), and drive (one Step call). Each mode yields at most
    /// one event before the loop runs again.
    /// </remarks>
    public bool MoveNext()
    {
        while (true)
        {
            // Pump-time-deferred Garbage half of a lex-failure pair: the
            // previous call returned the paired ErrorEvent; this call
            // returns the GarbageEvent carrying the bad codepoint.
            if (_pendingLexGarbage is not null)
            {
                _current = new GarbageEvent(_pendingLexGarbage);
                _pendingLexGarbage = null;
                return true;
            }
            if (PumpPending())
            {
                var t = _lex.NextToken();
                _cfg.ApplyActions(t.Kind, _lex);
                // Lex pattern miss — surface as a paired error+garbage
                // so the bad codepoint never enters lookahead. Keeps
                // dispatch's kind-based switch honest (it never has to
                // match against ErrorKind) and stops a stray bad byte
                // from pushing the parser out of an active Star into
                // SYNC recovery.
                if (t.Kind == Lexer.ErrorKind)
                {
                    _pendingLexGarbage = t;
                    _current = new ErrorEvent(new ParseError("unexpected character", t.Span));
                    return true;
                }
                if (_cfg.HasSkips && _cfg.IsSkip(t.Kind))
                {
                    // Skip tokens carry no label, so DropUnlabeledTokens
                    // would also drop them; the DropSkips gate is
                    // strictly tighter and runs first.
                    if (!_opts.DropSkips && !_opts.DropUnlabeledTokens)
                    {
                        _current = new TokenEvent(t);
                        return true;
                    }
                    continue;
                }
                for (int i = 0; i < _look.Length; i++)
                {
                    if (_look[i] is null) { _look[i] = t; break; }
                }
                continue;
            }
            // Lookahead is guaranteed to carry a real grammar kind —
            // pump strips lex failures before they reach the buffer.
            if (_recoveryActive)
            {
                ushort look0 = _look[0]!.Kind;
                bool synced = look0 == ParserConfig.EofKind
                    || ContainsKind(_recovery.Sync, look0);
                if (synced)
                {
                    bool wasExpected = _recovery.ExpectedPlusOne != 0
                        && (ushort)(_recovery.ExpectedPlusOne - 1) == look0;
                    _recoveryActive = false;
                    if (wasExpected)
                    {
                        // Honour the label filter on the recovered
                        // token (in practice the labeled-expect path
                        // doesn't run during recovery so the recovered
                        // token has no label; the gate is here for
                        // symmetry with drive-mode emit).
                        var ev = (TokenEvent)Consume();
                        if (_opts.DropUnlabeledTokens && ev.Token.Label is null)
                            continue;
                        _current = ev;
                        return true;
                    }
                    continue;
                }
                _current = new GarbageEvent(TakeToken());
                return true;
            }
            if (_state == Terminated)
            {
                // EOF gate. On the first visit with trailing input,
                // raise an error and arm a sync-empty recovery so the
                // rest of the input drains as Garbage events one per
                // call. Once recovery has eaten its way to EOF the
                // lookahead pins at EOF (the lexer keeps yielding it),
                // so this is naturally idempotent — subsequent visits
                // just return false.
                if (_look[0]!.Kind == ParserConfig.EofKind) { _current = null; return false; }
                _current = ErrorHere("expected end of input");
                _recovery = new Recovery { Sync = Array.Empty<ushort>(), ExpectedPlusOne = 0 };
                _recoveryActive = true;
                _lex.PopModesTo(1);
                return true;
            }
            var stepEv = _cfg.Step(new Cursor(this));
            if (stepEv is not null)
            {
                if (_opts.DropUnlabeledTokens
                    && stepEv is TokenEvent t2
                    && t2.Token.Label is null)
                {
                    continue;
                }
                _current = stepEv;
                return true;
            }
        }
    }

    public Event Current => _current!;
    object IEnumerator.Current => Current;
    public void Reset() => throw new NotSupportedException("Parser is single-pass.");
    public void Dispose() { }

    public IEnumerator<Event> GetEnumerator() => this;
    IEnumerator IEnumerable.GetEnumerator() => GetEnumerator();
}

/// <summary>The handle that generated Step bodies talk to the runtime
/// through. Wraps a <see cref="Parser"/> and re-exports just the
/// operations dispatch needs — lookahead access, return stack pushes,
/// event builders, recovery arming.</summary>
/// <remarks>
/// External code can't construct a <c>Cursor</c> (the constructor is
/// internal, and only <see cref="Parser.NextEvent"/> calls it), so the
/// only way one ever exists is inside a call to <see cref="ParserConfig.Step"/>
/// from the runtime's pull loop. That keeps the parser's internal state
/// from being poked at out of band.
/// </remarks>
public sealed class Cursor
{
    private readonly Parser _p;

    internal Cursor(Parser p) { _p = p; }

    /// <summary>Peek at the i-th lookahead token. Generated <c>Step</c>
    /// only runs after pump-mode has filled every slot.</summary>
    public Token Look(int i) => _p._look[i]!;

    /// <summary>Current state id. Read at the top of every step iteration.</summary>
    public int State() => _p._state;

    /// <summary>Overwrite the current state id.</summary>
    public void SetState(int s) => _p._state = s;

    /// <summary>Push a return address onto the call stack along with
    /// the current lex mode-stack depth, so recovery can unwind
    /// interior mode pushes back to the depth in place when this
    /// rule started.</summary>
    public void PushRet(int s)
    {
        _p._ret.Push(s);
        _p._retModeDepth.Push(_p._lex.ModeDepth);
    }

    /// <summary>Pop the top return address, or <see cref="Parser.Terminated"/>
    /// when the stack is empty.</summary>
    public int PopRet()
    {
        if (_p._ret.Count == 0) return Parser.Terminated;
        _p._retModeDepth.Pop();
        return _p._ret.Pop();
    }

    /// <summary>True iff the current lookahead matches any of the given
    /// prefixes.</summary>
    public bool MatchesFirst(ushort[][] set)
    {
        foreach (var seq in set)
        {
            bool match = true;
            for (int i = 0; i < seq.Length; i++)
            {
                if (_p._look[i]!.Kind != seq[i]) { match = false; break; }
            }
            if (match) return true;
        }
        return false;
    }

    /// <summary>Build an Enter event for <paramref name="rule"/>.
    /// Records the rule's start position so a later Exit without any
    /// intervening tokens still produces a zero-width span at the
    /// expected place.</summary>
    public Event Enter(int rule)
    {
        var pos = _p._look[0]!.Span.Start;
        _p._prevEnd = pos;
        return new EnterEvent(rule, pos);
    }

    /// <summary>Build an Exit event for <paramref name="rule"/>,
    /// positioned at the end of the last consumed token (or the rule's
    /// start for empty rules).</summary>
    public Event Exit(int rule) => new ExitEvent(rule, _p._prevEnd);

    /// <summary>Consume the current lookahead token and return it as a
    /// <see cref="TokenEvent"/>. Used on TryConsume's success path and
    /// on recovery's "synced-to-expected" path — both yield legitimate
    /// parse data.</summary>
    public Event Consume() => _p.Consume();

    /// <summary>Try to consume a token of <paramref name="kind"/>. On a
    /// hit returns a <see cref="TokenEvent"/>. On a miss returns an
    /// <see cref="ErrorEvent"/> and arms recovery — subsequent
    /// <see cref="Parser.NextEvent"/> calls skip <see cref="GarbageEvent"/>s
    /// one at a time until the lookahead lands on <paramref name="sync"/>
    /// (when it does, the matching token comes through as a normal
    /// <see cref="TokenEvent"/>).</summary>
    public Event TryConsume(ushort kind, ushort[] sync, string name) =>
        TryConsumeLabeled(kind, sync, name, null);

    /// <summary><see cref="TryConsume"/> with a <paramref name="label"/>
    /// stamped on the consumed token's <see cref="Token.Label"/> on the
    /// success path. Used by generated dispatch for <c>name:NAME</c>
    /// positions; the label travels through to the consumer's event
    /// stream so they can identify the position by name without
    /// tracking surrounding rule context. Pass <c>null</c> for
    /// unlabeled positions.</summary>
    public Event TryConsumeLabeled(ushort kind, ushort[] sync, string name, string? label)
    {
        if (_p._look[0]!.Kind == kind)
        {
            // `Token` is an immutable record — use `with` to stamp the
            // label and write it back into the lookahead slot before
            // Consume rotates it out.
            if (label is not null)
            {
                _p._look[0] = _p._look[0]! with { Label = label };
            }
            return _p.Consume();
        }
        var ev = _p.ErrorHere($"expected {name}");
        _p._recovery = new Parser.Recovery { Sync = sync, ExpectedPlusOne = kind + 1 };
        _p._recoveryActive = true;
        UnwindModes();
        return ev;
    }

    /// <summary>Arm recovery without an expected kind. Called from a
    /// dispatch error leaf: the surrounding <c>cur</c> is already
    /// pointing at the post-recovery state, and the returned
    /// <see cref="ErrorEvent"/> makes Step yield so recovery-mode can
    /// take over.</summary>
    public void RecoverTo(ushort[] sync)
    {
        _p._recovery = new Parser.Recovery { Sync = sync, ExpectedPlusOne = 0 };
        _p._recoveryActive = true;
        UnwindModes();
    }

    /// <summary>Unwind any interior lex mode pushes the now-erroring
    /// rule made. The top of <see cref="Parser._retModeDepth"/> is the
    /// depth at the moment the rule we're inside was entered; popping
    /// back to it brings the lexer to the same context the surrounding
    /// caller expects. With an empty stack (recovery in the entry
    /// rule) we restore to depth 1 — the default mode.</summary>
    private void UnwindModes()
    {
        var target = _p._retModeDepth.Count > 0 ? _p._retModeDepth.Peek() : 1;
        _p._lex.PopModesTo(target);
    }

    /// <summary>Build a recoverable error event at the current
    /// lookahead.</summary>
    public Event ErrorHere(string msg) => _p.ErrorHere(msg);
}
